```cpp
#include <iostream>
using namespace std;

class Stack {
private:
    int arr[100];   // Array to store stack elements
    int topIndex;   // Index of the top element

public:
    // Constructor to initialize stack
    Stack() {
        topIndex = -1;  // Stack is initially empty
    }

    // Check if stack is empty
    bool empty() {
        return topIndex == -1;
    }

    // Check if stack is full
    bool full() {
        return topIndex == 99;
    }

    // Push an element onto the stack
    bool push(int x) {
        if (full()) {
            cout << "Stack overflow! Cannot push " << x << endl;
            return false;
        }
        arr[++topIndex] = x;
        return true;
    }

    // Pop the top element from the stack
    bool pop() {
        if (empty()) {
            cout << "Stack underflow! Cannot pop." << endl;
            return false;
        }
        topIndex--;
        return true;
    }

    // Get the top element of the stack
    int top() {
        if (empty()) {
            cout << "Stack is empty! No top element." << endl;
            return -1; // or throw an exception
        }
        return arr[topIndex];
    }
};

int main() {
    Stack s;

    s.push(10);
    s.push(20);
    s.push(30);

    cout << "Top element: " << s.top() << endl; // Should print 30

    s.pop();
    cout << "Top element after pop: " << s.top() << endl; // Should print 20

    while (!s.empty()) {
        cout << "Popping: " << s.top() << endl;
        s.pop();
    }

    s.pop(); // Trying to pop from empty stack

    return 0;
}
```
**Explanation:**

- The stack is implemented using a fixed-size array of 100 integers.
- `topIndex` keeps track of the current top element's index. It starts at -1 indicating the stack is empty.
- `empty()` returns true if the stack has no elements.
- `full()` returns true if the stack has reached its maximum capacity.
- `push(int x)` adds an element to the top if the stack is not full.
- `pop()` removes the top element if the stack is not empty.
- `top()` returns the current top element or -1 if the stack is empty.
- The `main()` function demonstrates usage of the stack.
